import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const KALSHI_ID = "5cc326fb-500d-4c17-bc5f-ade143210636";

  // 1. Search for the top Trump tariffs market
  const searchResult = await callMcpSkill({
    toolId: KALSHI_ID,
    toolName: "search_markets",
    args: { query: "Trump tariffs", limit: 1, status: "open" }
  });

  const markets = Array.isArray(searchResult?.results) ? searchResult.results : [];
  if (markets.length === 0) {
    return { error: "No active Trump tariffs markets found." };
  }

  const topMarket = markets[0];
  const ticker = topMarket.ticker;

  // 2. Analyze sentiment and price trend for the specific ticker
  const sentimentResult = await callMcpSkill({
    toolId: KALSHI_ID,
    toolName: "analyze_market_sentiment",
    args: { ticker: ticker, periodHours: 24 }
  });

  return {
    marketTitle: topMarket.title,
    url: topMarket.url,
    ticker: ticker,
    analysis: sentimentResult
  };
}

